INSERT INTO public.components (id, component, user_id, uuid, application_id) VALUES (427, '{"name": "text_input", "root": true, "type": "text_input", "uuid": "e44af537-ccb6-4086-af23-d537b186df36", "input": {"type": {"type": "string", "value": "number"}, "label": {"type": "value", "value": "text"}, "value": {"type": "value", "value": "bien"}, "helper": {"type": "value", "value": "saisir"}, "placeholder": {"type": "value", "value": "bbb"}}, "style": {"size": "medium", "--hybrid-input-label-font-size": "24px", "--hybrid-input-helper-text-font-size": "19px"}, "pageId": "fd444c12-3598-47e0-b1f5-1ac9a622c568", "children_ids": [], "application_id": "2e6cbbc8-59f5-445d-b8bb-542020b78dab"}', '7a44cfff-24d1-4eec-8974-c6384303f1ba', 'e44af537-ccb6-4086-af23-d537b186df36', '2e6cbbc8-59f5-445d-b8bb-542020b78dab') ON CONFLICT DO NOTHING;
INSERT INTO public.components (id, component, user_id, uuid, application_id) VALUES (864, '{"name": "left-menuz_znn", "type": "container", "uuid": "bc4be638-c9c1-4580-885e-d5ff1229e972", "event": {"onInit": "/**\n * Fetches the storage tree and transforms it into a menu structure\n * @param {string} userId - The user ID to fetch the storage tree for\n * @param {number} maxDepth - The maximum depth to traverse (-1 for unlimited)\n * @returns {Promise<Array>} - The menu structure based on the storage tree\n */\n\n\nconst currentEditingApplication = GetVar(\"currentEditingApplication\");\nVars.mainFolder = currentEditingApplication.uuid;\nasync function fetchStorageTree(userId = currentEditingApplication.uuid, maxDepth = -1) {\n  try {\n    // Fetch the storage tree from the API\n    const response = await fetch(`/api/v1/storage/tree/${userId}?maxDepth=${maxDepth}`);\n    \n    if (!response.ok) {\n      throw new Error(`Failed to fetch storage tree: ${response.status} ${response.statusText}`);\n    }\n    \n    const data = await response.json();\n      console.log(''data'', data, ''data'')\n    // Transform the storage tree into a menu structure\n    const result = transformToMenu(data);\n    \n    const docs = [\n      { id  :  Vars.mainFolder,\n        icon: \"folder\" ,\n        opened : true,\n        text : Vars.mainFolder,\n        value : Vars.mainFolder,\n        children : result,\n        menu: {}}\n    ]\n    Vars.documents = docs;\n    console.log(docs)\n    return result;\n  } catch (error) {\n    console.error(''Error fetching storage tree:'', error);\n    throw error;\n  }\n}\n\n/**\n * Recursively transforms a storage tree node into a menu structure\n * @param {Object} node - The storage tree node to transform\n * @returns {Object} - The transformed menu item\n */\nfunction transformToMenu(node) {\n  // Skip directly to children if this is the root node\n  if (node.path === `${node.name}/`) {\n    return node.children.map(child => createMenuItem(child));\n  }\n  \n  return createMenuItem(node);\n}\n\n/**\n * Creates a menu item from a storage tree node\n * @param {Object} node - The storage tree node\n * @returns {Object} - The menu item\n */\nfunction createMenuItem(node) {\n  const isDirectory = !node.isFile;\n  const id = node.path;\n  const text = node.name;\n  const value = node.path;\n  \n  const menuItem = {\n    id,\n    icon: isDirectory ? \"folder\" : getFileIcon(node.name, node.contentType),\n    text,\n    value,\n    menu: {}\n  };\n  \n  // Add children if this is a directory and has children\n  if (isDirectory && node.children && node.children.length > 0) {\n    menuItem.children = node.children.map(child => createMenuItem(child));\n    \n    // If the folder has children and is expanded, update the icon\n    if (menuItem.children.length > 0) {\n      // You can implement logic here to determine if a folder should be open by default\n      // For now, we''ll just use folder-open for directories with children\n      menuItem.icon = \"folder-open\";\n    }\n  }\n  \n  return menuItem;\n}\n\n/**\n * Gets the appropriate icon for a file based on its extension and content type\n * @param {string} fileName - The file name\n * @param {string} contentType - The content type\n * @returns {string} - The icon name\n */\nfunction getFileIcon(fileName, contentType) {\n  if (!fileName) return \"file\";\n  \n  const extension = fileName.split(''.'').pop().toLowerCase();\n  \n  // Handle image files\n  if (contentType && contentType.startsWith(''image/'')) {\n    return \"image\";\n  }\n  \n  // Handle specific file types based on extension\n  switch (extension) {\n    case ''pdf'':\n      return \"file-pdf\";\n    case ''doc'':\n    case ''docx'':\n      return \"file-word\";\n    case ''xls'':\n    case ''xlsx'':\n      return \"file-excel\";\n    case ''ppt'':\n    case ''pptx'':\n      return \"file-powerpoint\";\n    case ''txt'':\n      return \"file-text\";\n    case ''zip'':\n    case ''rar'':\n    case ''gz'':\n    case ''tar'':\n      return \"file-zip\";\n    case ''mp3'':\n    case ''wav'':\n    case ''ogg'':\n      return \"file-audio\";\n    case ''mp4'':\n    case ''avi'':\n    case ''mov'':\n      return \"file-video\";\n    case ''js'':\n    case ''ts'':\n    case ''jsx'':\n    case ''tsx'':\n      return \"file-code\";\n    case ''json'':\n      return \"file-json\";\n    default:\n      return \"file\";\n  }\n}\nVars.fetchStorageTree = fetchStorageTree;\n (async () => {\n  await fetchStorageTree(Vars.mainFolder, -1);\n})();"}, "style": {"width": "200px"}, "pageId": "4ed746d4-e205-46f2-9ef1-3c7ad9c337d8", "childrens": [{"name": "menu_3022", "type": "menu", "uuid": "2837e2a0-9a77-449d-8ed3-ed8cafc15e37", "input": {"options": {"type": "handler", "value": " \n/**\n * Fetches the storage tree and transforms it into a menu structure\n * @param {string} userId - The user ID to fetch the storage tree for\n * @param {number} maxDepth - The maximum depth to traverse (-1 for unlimited)\n * @returns {Promise<Array>} - The menu structure based on the storage tree\n */\nasync function fetchStorageTree(userId = ''my-folder'', maxDepth = -1) {\n  try {\n    // Fetch the storage tree from the API\n    const response = await fetch(`/api/v1/storage/tree/${userId}?maxDepth=${maxDepth}`);\n    \n    if (!response.ok) {\n      throw new Error(`Failed to fetch storage tree: ${response.status} ${response.statusText}`);\n    }\n    \n    const data = await response.json();\n    \n    // Transform the storage tree into a menu structure\n    return transformToMenu(data);\n  } catch (error) {\n    console.error(''Error fetching storage tree:'', error);\n    throw error;\n  }\n}\n\n/**\n * Recursively transforms a storage tree node into a menu structure\n * @param {Object} node - The storage tree node to transform\n * @returns {Object} - The transformed menu item\n */\nfunction transformToMenu(node) {\n  // Skip directly to children if this is the root node\n  if (node.path === `${node.name}/`) {\n    return node.children.map(child => createMenuItem(child));\n  }\n  \n  return createMenuItem(node);\n}\n\n/**\n * Creates a menu item from a storage tree node\n * @param {Object} node - The storage tree node\n * @returns {Object} - The menu item\n */\nfunction createMenuItem(node) {\n  const isDirectory = !node.isFile;\n  const id = node.path.replace(/\\//g, ''-'');\n  const text = node.name;\n  const value = node.path;\n  \n  const menuItem = {\n    id,\n    icon: isDirectory ? \"folder\" : getFileIcon(node.name, node.contentType),\n    text,\n    value,\n    menu: {}\n  };\n  \n  // Add children if this is a directory and has children\n  if (isDirectory && node.children && node.children.length > 0) {\n    menuItem.children = node.children.map(child => createMenuItem(child));\n    \n    // If the folder has children and is expanded, update the icon\n    if (menuItem.children.length > 0) {\n      // You can implement logic here to determine if a folder should be open by default\n      // For now, we''ll just use folder-open for directories with children\n      menuItem.icon = \"folder-open\";\n    }\n  }\n  \n  return menuItem;\n}\n\n/**\n * Gets the appropriate icon for a file based on its extension and content type\n * @param {string} fileName - The file name\n * @param {string} contentType - The content type\n * @returns {string} - The icon name\n */\nfunction getFileIcon(fileName, contentType) {\n  if (!fileName) return \"file\";\n  \n  const extension = fileName.split(''.'').pop().toLowerCase();\n  \n  // Handle image files\n  if (contentType && contentType.startsWith(''image/'')) {\n    return \"image\";\n  }\n  \n  // Handle specific file types based on extension\n  switch (extension) {\n    case ''pdf'':\n      return \"file-pdf\";\n    case ''doc'':\n    case ''docx'':\n      return \"file-word\";\n    case ''xls'':\n    case ''xlsx'':\n      return \"file-excel\";\n    case ''ppt'':\n    case ''pptx'':\n      return \"file-powerpoint\";\n    case ''txt'':\n      return \"file-text\";\n    case ''zip'':\n    case ''rar'':\n    case ''gz'':\n    case ''tar'':\n      return \"file-zip\";\n    case ''mp3'':\n    case ''wav'':\n    case ''ogg'':\n      return \"file-audio\";\n    case ''mp4'':\n    case ''avi'':\n    case ''mov'':\n      return \"file-video\";\n    case ''js'':\n    case ''ts'':\n    case ''jsx'':\n    case ''tsx'':\n      return \"file-code\";\n    case ''json'':\n      return \"file-json\";\n    default:\n      return \"file\";\n  }\n}\n\nreturn fetchStorageTree(''my-folder'', -1)"}}, "style": {"width": "100%", "--hybrid-menu-border": "none", "--hybrid-menu-font-size": "12px", "--hybrid-sub-menu-padding-y": "4px", "--hybrid-menu-link-padding-y": "4px", "--hybrid-sub-menu-highlighted-background-color": "transparent"}, "pageId": "3334730f-4c02-4221-b63c-fef126885366", "childrens": [], "children_ids": [], "application_id": "7c3b15ec-0d2c-4457-9172-e4da73585ca7"}, {"name": "text_label_5430", "type": "text_label", "uuid": "d2dabbfd-fe42-4bc6-983c-b283ee4f06ed", "pageId": "3334730f-4c02-4221-b63c-fef126885366", "childrens": [], "children_ids": [], "application_id": "7c3b15ec-0d2c-4457-9172-e4da73585ca7"}], "children_ids": ["7397ce58-e6ad-4b00-9e55-20b3a0384a26", "e607c26d-7e53-4085-80c2-6c2635a119cf"], "application_id": "e58edd43-385c-4900-b322-dbfdd4f1dc77"}', '7a44cfff-24d1-4eec-8974-c6384303f1ba', 'bc4be638-c9c1-4580-885e-d5ff1229e972', 'e58edd43-385c-4900-b322-dbfdd4f1dc77') ON CONFLICT DO NOTHING;
