INSERT INTO public.components (id, component, user_id, uuid, application_id) VALUES (879, '{"name": "data_sec", "type": "container", "uuid": "cbc4ccd0-09be-4191-9f55-f153d9f3eb36", "event": {"onInit": "// Store the last browsed folder path\nVars.lastBrowsedFolder = Vars.lastBrowsedFolder ?? null;\n    console.log(Vars.currentUploadFolder, Vars.lastBrowsedFolder )\n\nVars.browseFolder = async function() {\n    Vars.dataIsLoading = true;\n    // Get the current folder path\n    const currentFolder = Vars.currentUploadFolder ?? Vars.mainFolder;\n    \n    // Check if the folder path has changed\n    if (Vars.lastBrowsedFolder === currentFolder) {\n        console.log(''Folder path unchanged, skipping browse operation'');\n        //return; // Break out of the function if path hasn''t changed\n    }\n    \n    // Save the current folder path for future comparison\n    Vars.lastBrowsedFolder = currentFolder;\n    \n    // Continue with the original browse functionality\n    const result = await FileStorage.browse({\n        folderPath: currentFolder\n    });\n    console.log(result);\n    \n    const browseResult = [\n        ...result.folders.map((folder) => {\n            return {\n                name: folder.name,\n                path: folder.path,\n                type: ''folder'',\n            };\n        }),\n        ...result.files.map((file) => {\n            return {\n                name: file.name,\n                contentType: file.contentType,\n                type: ''file'',\n            };\n        }),\n    ];\n    \n    //Vars.browseResult = [];\n   // setTimeout(() => {\n        Vars.browseResult = [...browseResult];\n        Vars.dataIsLoading = false;\n        if(!Vars.browseResult.length){\n            Vars.filled = true;\n        }else{\n             Vars.filled = false;\n        }\n   // }, 10);\n    \n    console.log(''Vars.browseResult'', [...browseResult]);\n};\n\n// Call the function\nVars.browseFolder();"}, "input": {"direction": {"type": "string", "value": "vertical"}}, "style": {"flex": "1", "width": "", "height": "", "display": "flex", "align-items": "start", "padding-top": "20px", "padding-left": "20px", "padding-right": "20px", "padding-bottom": "20px", "justify-content": "start"}, "pageId": "4ed746d4-e205-46f2-9ef1-3c7ad9c337d8", "childrens": [{"name": "Collection_6487", "type": "collection", "uuid": "3d5021e8-6b71-452b-833b-3d7f8b0820b0", "input": {"data": {"type": "handler", "value": "return Vars.browseResult  ?? []"}}, "style": {"--columns": "6"}, "pageId": "3334730f-4c02-4221-b63c-fef126885366", "childrens": [{"name": "container-block_3242", "type": "container", "uuid": "41985797-fae5-4594-b366-e1726f6f1bba", "input": {"direction": {"type": "string", "value": "vertical"}}, "style": {"display": "flex", "align-items": "center", "padding-top": "20px", "padding-left": "20px", "padding-right": "20px", "padding-bottom": "20px", "justify-content": "center"}, "pageId": "3334730f-4c02-4221-b63c-fef126885366", "childrens": [{"name": "Icon_4726", "type": "icon", "uuid": "025080d2-4658-42cd-b0e6-0cb9885d07b8", "input": {"icon": {"type": "handler", "value": "return Item.type == \"file\" ? \"file\" : \"folder\";"}}, "style": {"width": "50px", "height": "50px", "--hybrid-icon-color": "#5c5c5c"}, "pageId": "3334730f-4c02-4221-b63c-fef126885366", "childrens": [], "children_ids": [], "application_id": "7c3b15ec-0d2c-4457-9172-e4da73585ca7"}, {"name": "text_label_894", "type": "text_label", "uuid": "0ec98fef-a77b-4a87-a1bd-b4403622835e", "input": {"value": {"type": "handler", "value": "return Item.name;"}}, "pageId": "3334730f-4c02-4221-b63c-fef126885366", "childrens": [], "children_ids": [], "application_id": "7c3b15ec-0d2c-4457-9172-e4da73585ca7"}], "children_ids": ["025080d2-4658-42cd-b0e6-0cb9885d07b8", "0ec98fef-a77b-4a87-a1bd-b4403622835e"], "application_id": "7c3b15ec-0d2c-4457-9172-e4da73585ca7"}], "children_ids": ["41985797-fae5-4594-b366-e1726f6f1bba"], "application_id": "7c3b15ec-0d2c-4457-9172-e4da73