INSERT INTO public.components (id, component, user_id, uuid, application_id) VALUES (882, '{"name": "conter-block_8fch", "type": "container", "uuid": "7f4b20f4-b4e3-47fc-acb1-1ac11b3f3a15", "input": {"direction": {"type": "string", "value": "horizontal"}}, "pageId": "4ed746d4-e205-46f2-9ef1-3c7ad9c337d8", "childrens": [{"name": "container-block_3392", "type": "container", "uuid": "8032f87b-df24-413a-b6d3-5595ccea4ff2", "event": {"onInit": "/**\n * Fetches the storage tree and transforms it into a menu structure\n * @param {string} userId - The user ID to fetch the storage tree for\n * @param {number} maxDepth - The maximum depth to traverse (-1 for unlimited)\n * @returns {Promise<Array>} - The menu structure based on the storage tree\n */\nVars.mainFolder = \"my-folder\";\nasync function fetchStorageTree(userId = ''my-folder'', maxDepth = -1) {\n  try {\n    // Fetch the storage tree from the API\n    const response = await fetch(`/api/v1/storage/tree/${userId}?maxDepth=${maxDepth}`);\n    \n    if (!response.ok) {\n      throw new Error(`Failed to fetch storage tree: ${response.status} ${response.statusText}`);\n    }\n    \n    const data = await response.json();\n      console.log(''data'', data, ''data'')\n    // Transform the storage tree into a menu structure\n    return transformToMenu(data);\n  } catch (error) {\n    console.error(''Error fetching storage tree:'', error);\n    throw error;\n  }\n}\n\n/**\n * Recursively transforms a storage tree node into a menu structure\n * @param {Object} node - The storage tree node to transform\n * @returns {Object} - The transformed menu item\n */\nfunction transformToMenu(node) {\n  // Skip directly to children if this is the root node\n  if (node.path === `${node.name}/`) {\n    return node.children.map(child => createMenuItem(child));\n  }\n  \n  return createMenuItem(node);\n}\n\n/**\n * Creates a menu item from a storage tree node\n * @param {Object} node - The storage tree node\n * @returns {Object} - The menu item\n */\nfunction createMenuItem(node) {\n  const isDirectory = !node.isFile;\n  const id = node.path;\n  const text = node.name;\n  const value = node.path;\n  \n  const menuItem = {\n    id,\n    icon: isDirectory ? \"folder\" : getFileIcon(node.name, node.contentType),\n    text,\n    value,\n    menu: {}\n  };\n  \n  // Add children if this is a directory and has children\n  if (isDirectory && node.children && node.children.length > 0) {\n    menuItem.children = node.children.map(child => createMenuItem(child));\n    \n    // If the folder has children and is expanded, update the icon\n    if (menuItem.children.length > 0) {\n      // You can implement logic here to determine if a folder should be open by default\n      // For now, we''ll just use folder-open for directories with children\n      menuItem.icon = \"folder-open\";\n    }\n  }\n  \n  return menuItem;\n}\n\n/**\n * Gets the appropriate icon for a file based on its extension and content type\n * @param {string} fileName - The file name\n * @param {string} contentType - The content type\n * @returns {string} - The icon name\n */\nfunction getFileIcon(fileName, contentType) {\n  if (!fileName) return \"file\";\n  \n  const extension = fileName.split(''.'').pop().toLowerCase();\n  \n  // Handle image files\n  if (contentType && contentType.startsWith(''image/'')) {\n    return \"image\";\n  }\n  \n  // Handle specific file types based on extension\n  switch (extension) {\n    case ''pdf'':\n      return \"file-pdf\";\n    case ''doc'':\n    case ''docx'':\n      return \"file-word\";\n    case ''xls'':\n    case ''xlsx'':\n      return \"file-excel\";\n    case ''ppt'':\n    case ''pptx'':\n      return \"file-powerpoint\";\n    case ''txt'':\n      return \"file-text\";\n    case ''zip'':\n    case ''rar'':\n    case ''gz'':\n    case ''tar'':\n      return \"file-zip\";\n    case ''mp3'':\n    case ''wav'':\n    case ''ogg'':\n      return \"file-audio\";\n    case ''mp4'':\n    case ''avi'':\n    case ''mov'':\n      return \"file-video\";\n    case ''js'':\n    case ''ts'':\n    case ''jsx'':\n    case ''tsx'':\n      return \"file-code\";\n    case ''json'':\n      return \"file-json\";\n    default:\n      return \"file\";\n  }\n}\nVars.fetchStorageTree = fetchStorageTree;\n (async () => {\n  const result = await fetchStorageTree(Vars.mainFolder, -1)\n  Vars.documents =result;\n  return result\n})();"}, "style": {"width": "200px"}, "pageId": "3334730f-4c02-4221-b63c-fef126885366", "childrens": [{"name": "text_label_5430", "type": "text_label", "uuid": "d2dabbfd-fe42-4bc6-983c-b283ee4f06ed", "input": {"value": {"type": "value", "value": "Files"}}, "style": {"fontSize": "32px", "font-family": "\"Mulish\", sans-serif", "margin-left": "10px"}, "pageId": "3334730f-4c02-4221-b63c-fef126885366", "childrens": [], "children_ids": [], "application_id": "7c3b15ec-0d2c-4457-9172-e4da73585ca7"}, {"name": "menu_3022", "type": "menu", "uuid": "2837e2a0-9a77-449d-8ed3-ed8cafc15e37", "event": {"onSelect": "const hasExtension = /\\.[^\\/]+$/.test(EventData.page);\n\nif (hasExtension) {\n  // Remove the file name, keep the folder path\n  Vars.currentUploadFolder = EventData.page.substring(0, EventData.page.lastIndexOf(\"/\"));\n} else {\n  // It''s already a folder path\n  Vars.currentUploadFolder = EventData.page;\n}\n\nsetTimeout(() => {\n  Vars.browseFolder();\n}, 60);"}, "input": {"options": {"type": "handler", "value": " return Vars.documents;"}}, "style": {"width": "100%", "height": "400px", "margin-left": "10px", "--hybrid-menu-border": "none", "--hybrid-menu-font-size": "12px", "--hybrid-sub-menu-padding-y": "4px", "--hybrid-menu-link-padding-y": "4px", "--hybrid-sub-menu-highlighted-background-color": "transparent"}, "pageId": "3334730f-4c02-4221-b63c-fef126885366", "childrens": [], "children_ids": [], "application_id": "7c3b15ec-0d2c-4457-9172-e4da73585ca7"}], "children_ids": ["d2dabbfd-fe42-4bc6-983c-b283ee4f06ed", "2837e2a0-9a77-449d-8ed3-ed8cafc15e37"], "application_id": "7c3b15ec-0d2c-4457-9172-e4da73585ca7"}, {"name": "container-block_7226", "type": "container", "uuid": "dbd83297-284a-4f91-962a-e4e6780fe180", "event": {"onInit": "// Store the last browsed folder path\nVars.lastBrowsedFolder = Vars.lastBrowsedFolder ?? null;\n\nVars.browseFolder = async function() {\n    // Get the current folder path\n    const currentFolder = Vars.currentUploadFolder ?? Vars.mainFolder;\n    \n    // Check if the folder path has changed\n    if (Vars.lastBrowsedFolder === currentFolder) {\n        console.log(''Folder path unchanged, skipping browse operation'');\n        return; // Break out of the function if path hasn''t changed\n    }\n    \n    // Save the current folder path for future comparison\n    Vars.lastBrowsedFolder = currentFolder;\n    \n    // Continue with the original browse functionality\n    const result = await FileStorage.browse({\n        folderPath: currentFolder\n    });\n    console.log(result);\n    \n    const browseResult = [\n        ...result.folders.map((folder) => {\n            return {\n                name: folder.name,\n                path: folder.path,\n                type: ''folder'',\n            };\n        }),\n        ...result.files.map((file) => {\n            return {\n                name: file.name,\n                contentType: file.contentType,\n                type: ''file'',\n            };\n        }),\n    ];\n    \n    Vars.browseResult = [];\n    setTimeout(() => {\n        Vars.browseResult = [...browseResult];\n    }, 10);\n    \n    console.log(''Vars.browseResult'', [...browseResult]);\n};\n\n// Call the function\nVars.browseFolder();"}, "style": {"flex": "1", "width": "", "height": "", "display": "flex", "align-items": "start", "padding-top": "20px", "padding-left": "20px", "padding-right": "20px", "padding-bottom": "20px", "justify-content": "start"}, "pageId": "3334730f-4c02-4221-b63c-fef126885366", "childrens": [{"name": "text_label_1101", "type": "text_label", "uuid": "47a1e140-0603-4b2a-a7ca-73d68ba998ae", "input": {"value": {"type": "handler", "value": "return \"Current Folder Path: \" + (Vars.currentUploadFolder ?? Vars.mainFolder); "}, "height": {"type": "string", "value": "auto"}}, "style": {"height": "30px", "font-family": "\"Mulish\", sans-serif", "font-weight": "bold"}, "pageId": "3334730f-4c02-4221-b63c-fef126885366", "childrens": [], "children_ids": [], "application_id": "7c3b15ec-0d2c-4457-9172-e4da73585ca7"}, {"name": "Collection_6487", "type": "collection", "uuid": "3d5021e8-6b71-452b-833b-3d7f8b0820b0", "input": {"data": {"type": "handler", "value": "return Vars.browseResult ;"}}, "style": {"--columns": "6"}, "pageId": "3334730f-4c02-4221-b63c-fef126885366", "childrens": [{"name": "container-block_3242", "type": "container", "uuid": "41985797-fae5-4594-b366-e1726f6f1bba", "event": {"onClick": "Vars.selectedFile = Item", "onMouseEnter": ""}, "input": {"direction": {"type": "string", "value": "vertical"}}, "style": {"cursor": "pointer", "display": "flex", "align-items": "center", "padding-top": "20px", "padding-left": "20px", "padding-right": "20px", "padding-bottom": "20px", "justify-content": "center"}, "pageId": "3334730f-4c02-4221-b63c-fef126885366", "childrens": [{"name": "Icon_4726", "type": "icon", "uuid": "025080d2-4658-42cd-b0e6-0cb9885d07b8", "input": {"icon": {"type": "handler", "value": "return Item.type == \"file\" ? \"file\" : \"folder\";"}}, "style": {"width": "50px", "height": "50px", "--hybrid-icon-color": "#5e7f99"}, "pageId": "3334730f-4c02-4221-b63c-fef126885366", "childrens": [], "children_ids": [], "application_id": "7c3b15ec-0d2c-4457-9172-e4da73585ca7"}, {"name": "text_label_894", "type": "text_label", "uuid": "0ec98fef-a77b-4a87-a1bd-b4403622835e", "input": {"value": {"type": "handler", "value": "Vars.browseResult\nfunction shrinkMiddle(str, startLength = 5, endLength = 5) {\n  if (str.length <= startLength + endLength + 3) {\n    return str; // No need to shrink\n  }\n  return str.slice(0, startLength) + ''...'' + str.slice(-endLength);\n}\nreturn shrinkMiddle(Item.name , 10, 5);"}}, "pageId": "3334730f-4c02-4221-b63c-fef126885366", "childrens": [], "children_ids": [], "application_id": "7c3b15ec-0d2c-4457-9172-e4da73585ca7"}], "children_ids": ["025080d2-4658-42cd-b0e6-0cb9885d07b8", "0ec98fef-a77b-4a87-a1bd-b4403622835e"], "application_id": "7c3b15ec-0d2c-4457-9172-e4da73585ca7"}], "children_ids": ["41985797-fae5-4594-b366-e1726f6f1bba"], "application_id": "7c3b15ec-0d2c-4457-9172-e4da73585ca7"}], "children_ids": ["47a1e140-0603-4b2a-a7ca-73d68ba998ae", "3d5021e8-6b71-452b-833b-3d7f8b0820b0"], "application_id": "7c3b15ec-0d2c-4457-9172-e4da73585ca7"}, {"name": "text_label_5173", "type": "text_label", "uuid": "19c9665e-22cc-4466-92c6-ed226754c8a0", "pageId": "3334730f-4c02-4221-b63c-fef126885366", "childrens": [], "children_ids": [], "application_id": "7c3b15ec-0d2c-4457-9172-e4da73585ca7"}, {"name": "container-block_769", "type": "container", "uuid": "f7a48b3e-26ff-4ea2-977d-dd7ebaff177a", "input": {"direction": {"type": "string", "value": "vertical"}}, "pageId": "3334730f-4c02-4221-b63c-fef126885366", "childrens": [{"name": "text_label_9037", "type": "text_label", "uuid": "9a1c4d6b-f915-4459-94fa-b3cc4bef5691", "input": {"value": {"type": "handler", "value": "return Vars.selectedFile?.name ?? \"No file selected\";"}}, "style": {"fontSize": "22px", "font-weight": "300"}, "pageId": "3334730f-4c02-4221-b63c-fef126885366", "childrens": [], "children_ids": [], "application_id": "7c3b15ec-0d2c-4457-9172-e4da73585ca7"}, {"name": "Image_527", "type": "image", "uuid": "8ddc359a-68da-4c6c-b4dc-899a8c3d1180", "input": {"src": {"type": "handler", "value": "return `/api/v1/storage/preview/my-folder/${Vars.selectedFile.name}`"}}, "style": {"width": "294px", "height": "auto"}, "pageId": "3334730f-4c02-4221-b63c-fef126885366", "childrens": [], "children_ids": [], "application_id": "7c3b15ec-0d2c-4457-9172-e4da73585ca7"}], "children_ids": ["9a1c4d6b-f915-4459-94fa-b3cc4b