INSERT INTO public.components (id, component, user_id, uuid, application_id) VALUES (686, '{"name": "container-block_8108", "type": "container", "uuid": "2c31397d-84fb-4598-aa4f-97e98834b34f", "event": {"onInit": "// Existing load_functions method\nVars.load_functions = () => {\n    fetch(''/api/v1/functions'', {\n        method: ''GET'',\n        headers: {\n            ''Content-Type'': ''application/json'',\n        },\n    })\n    .then(response => {\n        if (!response.ok) {\n            // Handle non-OK response\n            throw new Error(`HTTP error! status: ${response.status}`);\n        }  \n        return response.json();\n    })\n    .then(data => {\n        console.log(\"data\", data); \n        Vars.studio_functions = data || [];\n        return data;\n    })\n    .catch(error => {\n        console.error(''Error fetching functions:'', error);\n        throw error; // Re-throw the error so the caller can handle it\n    });\n};\nVars.load_functions();\n// New create_function method\nVars.create_function = (newFunctionData) => {\n    return fetch(''/api/v1/functions'', {\n        method: ''POST'',\n        headers: {\n            ''Content-Type'': ''application/json'',\n        },\n        body: JSON.stringify(newFunctionData),\n    })\n    .then(response => {\n        if (!response.ok) {\n            // Handle non-OK response\n            return response.json().then(errData => {\n                const errorMessage = errData.message || `HTTP error! status: ${response.status}`;\n                throw new Error(errorMessage);\n            });\n        }\n        return response.json();\n    })\n    .then(createdFunction => {\n        console.log(\"Function created successfully:\", createdFunction);\n        Vars.studio_functions.push(createdFunction);\n        return createdFunction;\n    })\n    .catch(error => {\n        console.error(''Error creating function:'', error);\n        throw error; // Re-throw the error so the caller can handle it\n    });\n};\n\n\n/*Vars.create_function(newFunction)\n    .then(createdFunction => {\n        console.log(\"Created Function:\", createdFunction);\n        // Perform additional actions if needed\n    })\n    .catch(error => {\n        console.error(\"Failed to create function:\", error);\n    });*/"}, "pageId": "9671dd7f-e30a-4283-8a51-cd6ea3347944", "children_ids": ["42c059a8-07bb-45be-9a15-1286287bbf63"], "application_id": "31fe81f2-10ed-4ea2-b092-7ba3b39aae87"}', '7a44cfff-24d1-4eec-8974-c6384303f1ba', '2c31397d-84fb-4598-aa4f-97e98834b34f', '31fe81f2-10ed-4ea2-b092-7ba3b39aae87') ON CONFLICT DO NOTHING;
