INSERT INTO public.components (id, component, user_id, uuid, application_id) VALUES (788, '{"name": "text_input_2993", "type": "text_input", "uuid": "f8b9288c-600a-4f5f-9346-769c05d8b17f", "event": {"onChange": "if(!Vars.new_user.work ){\n    Vars.new_user.work ={}\n}\nVars.new_user.work.time_zone = EventData.value\nVars.new_user ={...Vars.new_user}\n"}, "input": {"label": {"type": "value", "value": "Timezone"}, "value": {"type": "handler", "value": "return  Vars.new_user.work.time_zone ?? \"\""}, "helper": {"type": "handler", "value": "return  Vars.new_user.work.time_zone ?? \"\""}, "placeholder": {"type": "value", "value": "GMT+1"}}, "pageId": "af1c4fb3-eb92-4a42-bdca-e2efed3a01dc", "children_ids": [], "application_id": "9632da77-caf2-42db-bce7-5248c5b13513"}', '7a44cfff-24d1-4eec-8974-c6384303f1ba', 'f8b9288c-600a-4f5f-9346-769c05d8b17f', '9632da77-caf2-42db-bce7-5248c5b13513') ON CONFLICT DO NOTHING;
INSERT INTO public.components (id, component, user_id, uuid, application_id) VALUES (523, '{"name": "container-block_9216", "type": "container", "uuid": "ee133314-0014-4e40-b067-9682331b1aa4", "input": {"layout": {"type": "string", "value": "boxed"}, "direction": {"type": "string", "value": "vertical"}, "innerAlignment": {"type": "string", "value": "middle"}}, "style": {"flex": "", "width": "650px", "display": "flex", "margin-top": "20px", "align-items": "start", "justify-content": "start"}, "pageId": "9461c09e-a437-49b0-9a51-d040d7edf431", "childrens": [{"name": "text_label_3184", "type": "text_label", "uuid": "ce54932e-c078-4eab-98c9-fb2d78dd98aa", "input": {"value": {"type": "value", "value": "Getting started"}}, "style": {"fontSize": "30px", "margin-top": "30px", "font-family": "\"Mulish\", sans-serif"}, "pageId": "9461c09e-a437-49b0-9a51-d040d7edf431", "childrens": [], "children_ids": [], "application_id": "838669d8-92d2-4342-baba-5f32a40eef42"}, {"name": "rich-text_1860_4wl8", "type": "rich_text", "uuid": "e1bfaeed-114a-48b7-9c95-b9ae0c41b0cd", "input": {"value": {"type": "string", "value": "Deno comes with many of the tools that are commonly needed for developing applications, including a full language server (LSP) to help power your IDE of choice. This page will help you set up your environment to get the most out of Deno while you are developing.<div><br></div><div>We''ll cover:&nbsp;</div><div><ul><li>How to use Deno with your favorite editor/IDE&nbsp;</li><li>How to generate shell completions</li></ul></div>"}}, "style": {"font-family": "\"Lato\", sans-serif"}, "pageId": "9461c09e-a437-49b0-9a51-d040d7edf431", "childrens": [], "children_ids": [], "application_id": "838669d8-92d2-4342-baba-5f32a40eef42"}, {"name": "text_label_3184_kptx_ugcp_ayf1", "type": "text_label", "uuid": "2ef55cbf-ace7-4dfb-8866-c87e6990a04d", "input": {"value": {"type": "value", "value": "Setting up your editor/IDE Jump to heading"}}, "style": {"flex": "", "width": "100%", "fontSize