INSERT INTO public.components (id, component, user_id, uuid, application_id) VALUES (886, '{"name": "file-upload_9726_4zta_ncgp", "type": "file_upload", "uuid": "f171a035-e282-40fe-801f-947d3ba1b480", "event": {"onFilesChanged": " (async () => {  \n      const {files} = EventData;\n      await FileStorage.upload({ files , folderPath : Vars.currentUploadFolder ?? Vars.mainFolder});\n      await Vars.fetchStorageTree(  Vars.mainFolder, -1)\n      await Vars.browseFolder(); \n})();"}, "input": {"label": {"type": "value", "value": " Check box"}}, "style": {"margin-left": "20px"}, "pageId": "4ed746d4-e205-46f2-9ef1-3c7ad9c337d8", "children_ids": [], "application_id": "e58edd43-385c-4900-b322-dbfdd4f1dc77"}', '7a44cfff-24d1-4eec-8974-c6384303f1ba', 'f171a035-e282-40fe-801f-947d3ba1b480', 'e58edd43-385c-4900-b322-dbfdd4f1dc77') ON CONFLICT DO NOTHING;
INSERT INTO public.components (id, component, user_id, uuid, application_id) VALUES (528, '{"name": "rich-text_1860_4wl8", "type": "rich_text", "uuid": "e1bfaeed-114a-48b7-9c95-b9ae0c41b0cd", "input": {"value": {"type": "string", "value": "Deno comes with many of the tools that are commonly needed for developing applications, including a full language server (LSP) to help power your IDE of choice. This page will help you set up your environment to get the most out of Deno while you are developing.<div><br></div><div>We''ll cover:&nbsp;</div><div><ul><li>How to use Deno with your favorite editor/IDE&nbsp;</li><li>How to generate shell completions</li></ul></div>"}}, "style": {"font-family": "\"Lato\", sans-serif"}, "pageId": "9461c09e-a437-49b0-9a51-d040d7edf431", "breakpoints": {"430px": {"input": {"value": {"type": "string", "value": "console.log(\"hello\")"}}}}, "children_ids": [], "application_id": "838669d8-92d2-4342-baba-5f32a40eef42"}', '7a44cfff-24d1-4eec-8974-c6384303f1ba', 'e1bfaeed-114a-48b7-9c95-b9ae0c41b0cd', '838669d8-92d2-4342-baba-5f32a40eef42') ON CONFLICT DO NOTHING;
