INSERT INTO public.components (id, component, user_id, uuid, application_id) VALUES (673, '{"name": "text_label_236_bo94", "type": "text_label", "uuid": "1d00d703-9424-493e-bb1a-bcf604041734", "input": {"value": {"type": "value", "value": "Quickly turn ideas into interactive prototypes using our AI-powered Copilot."}, "innerAlignment": {"type": "string", "value": "middle"}}, "style": {"display": "flex", "fontSize": "27px", "font-style": "italic", "margin-top": "50px", "align-items": "start", "font-family": "\"Lato\", sans-serif", "font-weight": "300", "padding-top": "10px", "padding-left": "40px", "padding-right": "40px", "padding-bottom": "10px", "justify-content": "center", "border-top-left-radius": "10px"}, "pageId": "bc16eab3-9d6d-433a-8550-53f26897574c", "childrens": [], "breakpoints": {"430px": {"input": {"value": {"type": "value", "value": "Quickly turn ideas into interactive prototypes using our AI-powered Copilot - no code needed."}}, "style": {"margin-top": "20px"}}}, "children_ids": [], "application_id": "862d84a4-0be4-4cd0-8255-77f270094ff8"}', '7a44cfff-24d1-4eec-8974-c6384303f1ba', '1d00d703-9424-493e-bb1a-bcf604041734', '862d84a4-0be4-4cd0-8255-77f270094ff8') ON CONFLICT DO NOTHING;
INSERT INTO public.components (id, component, user_id, uuid, application_id) VALUES (680, '{"name": "rich-text_5748", "type": "rich_text", "uuid": "d3e8a123-2dd9-4734-9e76-d36f46b9dbf1", "input": {"value": {"type": "string", "value": "<h1><div style=\"text-align: center;\"><span style=\"background-color: rgba(0, 0, 0, 0);\">Early access: FREE to use for now.</span></div><span style=\"font-weight: normal;\"><div style=\"text-align: center;\"><span style=\"font-size: large; background-color: rgba(0, 0, 0, 0);\">There will always be a free plan.&nbsp;</span></div></span></h1>"}}, "style": {"margin-top": "60px"}, "pageId": "bc16eab3-9d6d-433a-8550-53f26897574c", "breakpoints": {"430px": {"input": {"value": {"type": "string", "value": "<h1><div style=\"text-align: center;\"><span style=\"background-color: rgba(0, 0, 0, 0);\">Early access<br>FREE to use for now.</span></div><span style=\"font-weight: normal;\"><div style=\"text-align: center;\"><span style=\"font-size: large; background-color: rgba(0, 0, 0, 0);\">There will always be a free plan.&nbsp;</span></div></span></h1>"}}, "style": {"margin-top": "20px"}}}, "children_ids": [], "application_id": "862d84a4-0be4-4cd0-8255-77f270094ff8"}', '7a44cfff-24d1-4eec-8974-c6384303f1ba', 'd3e8a123-2dd9-4734-9e76-d36f46b9dbf1', '862d84a4-0be4-4cd0-8255-77f270094ff8') ON CONFLICT DO NOTHING;
